import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useChat } from '../contexts/ChatContext';
import { useWallet } from '../contexts/WalletContext';
import { useNFT } from '../contexts/NFTContext';
import {
  MessageSquare,
  Users,
  Lock,
  CheckCircle,
  XCircle,
  Crown,
  Plus,
  X,
  Trash2,
  AlertTriangle,
  LogOut
} from 'lucide-react';

const Dashboard = () => {
  const { chatRooms, createRoom, deleteRoom, leaveRoom } = useChat();
  const { walletAddress, ownedNFTs } = useWallet();
  const { listNFTForSale, marketplaceListings } = useNFT();
  const [showCreateRoom, setShowCreateRoom] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(null);
  const [showLeaveConfirm, setShowLeaveConfirm] = useState(null);
  const [activeTab, setActiveTab] = useState('all'); // 'all', 'created', 'joined'
  const [roomForm, setRoomForm] = useState({
    name: '',
    description: '',
    type: 'public',
    requiredNFT: '',
    nftOption: 'new', // 'new' or 'existing'
    existingNFTId: '',
    mintPrice: '',
    maxSupply: ''
  });

  const formatAddress = (address) => {
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const handleCreateRoom = async (e) => {
    e.preventDefault();
    if (roomForm.name.trim() && roomForm.description.trim()) {
      // Validate private room requirements
      if (roomForm.type === 'private') {
        if (roomForm.nftOption === 'new' && (!roomForm.mintPrice || !roomForm.maxSupply)) {
          alert('Please set both NFT price and max supply for new NFTs');
          return;
        }
        if (roomForm.nftOption === 'existing' && !roomForm.existingNFTId) {
          alert('Please select an existing NFT to use for room access');
          return;
        }
      }
      const newRoom = createRoom({
        ...roomForm,
        createdBy: walletAddress
      });

      // Handle private room NFT setup
      if (roomForm.type === 'private') {
        if (roomForm.nftOption === 'new' && roomForm.mintPrice && roomForm.maxSupply) {
          // Create new NFT listing
          try {
            await listNFTForSale({
              roomId: newRoom.id,
              roomName: roomForm.name,
              nftName: `${roomForm.name} Access Pass`,
              description: `Exclusive access to ${roomForm.name}. ${roomForm.description}`,
              price: roomForm.mintPrice,
              currency: 'ETH',
              seller: walletAddress,
              image: `https://via.placeholder.com/300/6366f1/ffffff?text=${encodeURIComponent(roomForm.name.slice(0, 10))}`,
              totalSupply: parseInt(roomForm.maxSupply),
            });
            
            alert(`🎉 Private room "${roomForm.name}" created successfully!\n\n✅ New room access NFTs are now available in the marketplace\n💰 Price: ${roomForm.mintPrice} ETH\n📦 Supply: ${roomForm.maxSupply} NFTs\n\nUsers can now purchase NFTs to gain access to your room!`);
          } catch (error) {
            console.error('Failed to list NFTs:', error);
            alert('Room created but failed to list NFTs in marketplace');
          }
        } else if (roomForm.nftOption === 'existing') {
          // Use existing NFT
          const existingNFT = marketplaceListings.find(nft => nft.id === roomForm.existingNFTId);
          if (existingNFT) {
            alert(`🎉 Private room "${roomForm.name}" created successfully!\n\n✅ Using existing NFT: "${existingNFT.nftName}"\n💰 Price: ${existingNFT.price} ETH\n\nUsers who own this NFT can now access your new room!`);
          }
        }
      }

      setRoomForm({ name: '', description: '', type: 'public', requiredNFT: '', nftOption: 'new', existingNFTId: '', mintPrice: '', maxSupply: '' });
      setShowCreateRoom(false);
    }
  };

  const handleInputChange = (field, value) => {
    setRoomForm(prev => ({ ...prev, [field]: value }));
  };

  const handleDeleteRoom = (roomId) => {
    deleteRoom(roomId);
    setShowDeleteConfirm(null);
  };

  const handleLeaveRoom = (roomId) => {
    leaveRoom(roomId);
    setShowLeaveConfirm(null);
  };

  const createdRooms = chatRooms.filter(room => room.createdBy === walletAddress);
  const joinedRooms = chatRooms.filter(room => room.hasAccess && room.createdBy !== walletAddress);
  
  const getFilteredRooms = () => {
    switch (activeTab) {
      case 'created':
        return createdRooms;
      case 'joined':
        return joinedRooms;
      default:
        return chatRooms;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
          <p className="text-gray-600">Welcome back, {formatAddress(walletAddress)}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-primary-100 rounded-lg flex items-center justify-center">
              <MessageSquare className="w-5 h-5 text-primary-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Available Rooms</p>
              <p className="text-2xl font-bold text-gray-900">
                {chatRooms.filter(room => room.hasAccess).length}
              </p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-blue-100 rounded-lg flex items-center justify-center">
              <Plus className="w-5 h-5 text-blue-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Rooms Created</p>
              <p className="text-2xl font-bold text-gray-900">{createdRooms.length}</p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-green-100 rounded-lg flex items-center justify-center">
              <Crown className="w-5 h-5 text-green-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Owned NFTs</p>
              <p className="text-2xl font-bold text-gray-900">{ownedNFTs.length}</p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 bg-purple-100 rounded-lg flex items-center justify-center">
              <Users className="w-5 h-5 text-purple-600" />
            </div>
            <div>
              <p className="text-sm text-gray-600">Total Members</p>
              <p className="text-2xl font-bold text-gray-900">
                {chatRooms.reduce((sum, room) => sum + room.memberCount, 0)}
              </p>
            </div>
          </div>
        </div>
      </div>

      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">Chat Rooms</h2>
          <div className="flex items-center space-x-4">
            <button
              onClick={() => setShowCreateRoom(true)}
              className="btn-primary flex items-center space-x-2"
            >
              <Plus className="w-4 h-4" />
              <span>Create Room</span>
            </button>
            <div className="flex items-center space-x-2 text-sm text-gray-500">
              <CheckCircle className="w-4 h-4 text-green-500" />
              <span>Access Granted</span>
              <XCircle className="w-4 h-4 text-red-500 ml-4" />
              <span>Access Denied</span>
            </div>
          </div>
        </div>

        {/* Room Filter Tabs */}
        <div className="flex space-x-1 mb-6 bg-gray-100 p-1 rounded-lg">
          <button
            onClick={() => setActiveTab('all')}
            className={`flex-1 py-2 px-4 rounded-md text-sm font-medium transition-colors duration-200 ${
              activeTab === 'all'
                ? 'bg-white text-gray-900 shadow-sm'
                : 'text-gray-600 hover:text-gray-900'
            }`}
          >
            All Rooms ({chatRooms.length})
          </button>
          <button
            onClick={() => setActiveTab('created')}
            className={`flex-1 py-2 px-4 rounded-md text-sm font-medium transition-colors duration-200 ${
              activeTab === 'created'
                ? 'bg-white text-gray-900 shadow-sm'
                : 'text-gray-600 hover:text-gray-900'
            }`}
          >
            Created ({createdRooms.length})
          </button>
          <button
            onClick={() => setActiveTab('joined')}
            className={`flex-1 py-2 px-4 rounded-md text-sm font-medium transition-colors duration-200 ${
              activeTab === 'joined'
                ? 'bg-white text-gray-900 shadow-sm'
                : 'text-gray-600 hover:text-gray-900'
            }`}
          >
            Joined ({joinedRooms.length})
          </button>
        </div>

        <div className="space-y-4">
          {getFilteredRooms().map((room) => (
            <div
              key={room.id}
              className={`p-4 rounded-lg border-2 transition-all duration-200 ${room.hasAccess
                ? 'border-green-200 bg-green-50 hover:bg-green-100'
                : 'border-red-200 bg-red-50'
                }`}
            >
              <div className="flex items-center justify-between">
                <div className="flex-1">
                  <div className="flex items-center space-x-3 mb-2">
                    <h3 className="font-semibold text-gray-900">{room.name}</h3>
                    {room.createdBy === walletAddress && (
                      <span className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">Creator</span>
                    )}
                    {room.type === 'private' && (
                      <span className="text-xs bg-purple-100 text-purple-700 px-2 py-1 rounded-full">NFT Gated</span>
                    )}
                    {room.hasAccess ? (
                      <CheckCircle className="w-5 h-5 text-green-500" />
                    ) : (
                      <Lock className="w-5 h-5 text-red-500" />
                    )}
                    {room.isActive && (
                      <div className="w-2 h-2 bg-green-400 rounded-full animate-pulse"></div>
                    )}
                  </div>
                  <p className="text-gray-600 text-sm mb-2">{room.description}</p>
                  <div className="flex items-center space-x-4 text-sm text-gray-500">
                    <span>
                      {room.type === 'private' 
                        ? `NFT Required (${room.mintPrice || '0.1'} ETH)` 
                        : 'Public Room'
                      }
                    </span>
                    <span>•</span>
                    <span>{room.memberCount} members</span>
                    {room.createdAt && (
                      <>
                        <span>•</span>
                        <span>Created: {room.createdAt.toLocaleDateString()}</span>
                      </>
                    )}
                  </div>
                </div>

                <div className="ml-4 flex items-center space-x-2">
                  {room.hasAccess ? (
                    <Link
                      to={`/room/${room.id}`}
                      className="btn-primary"
                    >
                      Enter Room
                    </Link>
                  ) : room.type === 'private' ? (
                    <Link
                      to="/marketplace"
                      className="px-4 py-2 bg-purple-600 hover:bg-purple-700 text-white rounded-lg transition-colors duration-200"
                    >
                      Buy NFT Access
                    </Link>
                  ) : (
                    <button
                      disabled
                      className="px-4 py-2 bg-gray-200 text-gray-500 rounded-lg cursor-not-allowed"
                    >
                      NFT Required
                    </button>
                  )}
                  
                  {/* Delete button for created rooms */}
                  {room.createdBy === walletAddress && (
                    <button
                      onClick={() => setShowDeleteConfirm(room)}
                      className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-colors duration-200"
                      title="Delete Room"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  )}
                  
                  {/* Leave button for joined rooms */}
                  {room.hasAccess && room.createdBy !== walletAddress && (
                    <button
                      onClick={() => setShowLeaveConfirm(room)}
                      className="p-2 text-orange-500 hover:bg-orange-50 rounded-lg transition-colors duration-200"
                      title="Leave Room"
                    >
                      <LogOut className="w-4 h-4" />
                    </button>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="card">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Your NFTs</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {ownedNFTs.map((nft) => (
            <div key={nft.id} className="border border-gray-200 rounded-lg p-4">
              <img
                src={nft.image}
                alt={nft.name}
                className="w-full h-32 object-cover rounded-lg mb-3"
              />
              <h3 className="font-medium text-gray-900">{nft.name}</h3>
              <p className="text-sm text-gray-600">{nft.collection}</p>
              <p className="text-xs text-gray-500">Token ID: {nft.tokenId}</p>
            </div>
          ))}
        </div>
      </div>

      {/* Create Room Modal */}
      {showCreateRoom && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-semibold text-gray-900">Create New Room</h3>
              <button
                onClick={() => setShowCreateRoom(false)}
                className="p-1 text-gray-400 hover:text-gray-600"
              >
                <X className="w-5 h-5" />
              </button>
            </div>

            <form onSubmit={handleCreateRoom} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Room Name *
                </label>
                <input
                  type="text"
                  value={roomForm.name}
                  onChange={(e) => handleInputChange('name', e.target.value)}
                  placeholder="Enter room name"
                  className="input-field"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Description *
                </label>
                <textarea
                  value={roomForm.description}
                  onChange={(e) => handleInputChange('description', e.target.value)}
                  placeholder="Describe your room..."
                  rows={3}
                  className="input-field resize-none"
                  required
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Room Type *
                </label>
                <select
                  value={roomForm.type}
                  onChange={(e) => handleInputChange('type', e.target.value)}
                  className="input-field"
                >
                  <option value="public">Public Room (Anyone can join)</option>
                  <option value="private">Private Room (NFT required)</option>
                </select>
                <p className="text-xs text-gray-500 mt-1">
                  {roomForm.type === 'public' 
                    ? 'Anyone can join this room freely'
                    : 'Users need to own your custom NFT to access this room'
                  }
                </p>
              </div>

              {roomForm.type === 'private' && (
                <>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        NFT Price (ETH)
                      </label>
                      <input
                        type="number"
                        step="0.001"
                        value={roomForm.mintPrice}
                        onChange={(e) => handleInputChange('mintPrice', e.target.value)}
                        placeholder="0.1"
                        className="input-field"
                      />
                    </div>
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-2">
                        Max Supply
                      </label>
                      <input
                        type="number"
                        value={roomForm.maxSupply}
                        onChange={(e) => handleInputChange('maxSupply', e.target.value)}
                        placeholder="100"
                        className="input-field"
                      />
                    </div>
                  </div>
                  <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
                    <p className="text-blue-700 text-sm">
                      💡 Creating a private room will automatically mint NFTs that users can purchase to gain access.
                    </p>
                  </div>
                </>
              )}

              <div className="flex space-x-3 pt-4">
                <button
                  type="button"
                  onClick={() => setShowCreateRoom(false)}
                  className="flex-1 btn-secondary"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="flex-1 btn-primary"
                >
                  Create Room
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Delete Room Confirmation Modal */}
      {showDeleteConfirm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <div className="flex items-center space-x-3 mb-4">
              <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center">
                <AlertTriangle className="w-5 h-5 text-red-600" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-gray-900">Delete Room</h3>
                <p className="text-sm text-gray-600">This action cannot be undone</p>
              </div>
            </div>
            
            <div className="mb-6">
              <p className="text-gray-700 mb-2">
                Are you sure you want to delete <strong>"{showDeleteConfirm.name}"</strong>?
              </p>
              <div className="bg-red-50 border border-red-200 rounded-lg p-3">
                <p className="text-red-700 text-sm">
                  • All messages in this room will be permanently deleted
                </p>
                <p className="text-red-700 text-sm">
                  • {showDeleteConfirm.memberCount} members will lose access
                </p>
                <p className="text-red-700 text-sm">
                  • This action cannot be reversed
                </p>
              </div>
            </div>

            <div className="flex space-x-3">
              <button
                onClick={() => setShowDeleteConfirm(null)}
                className="flex-1 btn-secondary"
              >
                Cancel
              </button>
              <button
                onClick={() => handleDeleteRoom(showDeleteConfirm.id)}
                className="flex-1 bg-red-600 hover:bg-red-700 text-white font-medium py-2 px-4 rounded-lg transition-colors duration-200"
              >
                Delete Room
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Leave Room Confirmation Modal */}
      {showLeaveConfirm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <div className="flex items-center space-x-3 mb-4">
              <div className="w-10 h-10 bg-orange-100 rounded-full flex items-center justify-center">
                <LogOut className="w-5 h-5 text-orange-600" />
              </div>
              <div>
                <h3 className="text-lg font-semibold text-gray-900">Leave Room</h3>
                <p className="text-sm text-gray-600">You can rejoin if you have the required NFT</p>
              </div>
            </div>
            
            <div className="mb-6">
              <p className="text-gray-700 mb-2">
                Are you sure you want to leave <strong>"{showLeaveConfirm.name}"</strong>?
              </p>
              <div className="bg-orange-50 border border-orange-200 rounded-lg p-3">
                <p className="text-orange-700 text-sm">
                  • You will lose access to this room and its messages
                </p>
                <p className="text-orange-700 text-sm">
                  • You can rejoin later if you still own the required NFT
                </p>
                <p className="text-orange-700 text-sm">
                  • Your previous messages will remain in the room
                </p>
              </div>
            </div>

            <div className="flex space-x-3">
              <button
                onClick={() => setShowLeaveConfirm(null)}
                className="flex-1 btn-secondary"
              >
                Cancel
              </button>
              <button
                onClick={() => handleLeaveRoom(showLeaveConfirm.id)}
                className="flex-1 bg-orange-600 hover:bg-orange-700 text-white font-medium py-2 px-4 rounded-lg transition-colors duration-200"
              >
                Leave Room
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
